parameters.jsCode:
const b = $json.body || {};
const contexto = `Briefing do anúncio:\n` +
  `- Objetivo: ${b.objetivo || 'engajamento'}\n` +
  `- Público-alvo: ${b.publico || 'geral'}\n` +
  `- Bairros: ${(b.bairros || []).join(', ') || '—'}\n` +
  `- Faixa etária: ${b.idadeMin || 18}-${b.idadeMax || 65}\n` +
  `- Gênero: ${b.genero || 'todos'}\n` +
  `- Orçamento diário: R$ ${b.budgetDiario || 30}\n` +
  `- Duração: ${b.duracaoDias || 7} dias\n` +
  `- Formato: ${b.formato || 'carrossel'}\n` +
  `- Tema/mensagem: ${b.tema || ''}`;
return { json: {
  openaiKey: b.openaiKey,
  openaiModel: b.openaiModel || 'gpt-4o-mini',
  contexto,
}};

parameters.jsonBody:
={
  "model": "{{ $json.openaiModel }}",
  "messages": [
    { "role": "system", "content": "Você é copywriter de tráfego pago do gabinete do vereador Marco Xavier (Limeira-SP, PP). Tom: próximo, popular, direto. Sem jargão político. Sem prometer obra. Apela aos valores de fé, família, união, luta por quem mais precisa. Use frases curtas. Responda APENAS em JSON válido com este formato: { \"titulo\": \"...\", \"texto_principal\": \"...\", \"cta\": \"Saiba mais\" | \"Enviar mensagem\" | \"Seguir\", \"prompt_imagem\": \"descrição visual pra criativo\", \"hashtags\": [\"#...\"] }" },
    { "role": "user", "content": {{ JSON.stringify($json.contexto) }} }
  ],
  "temperature": 0.8,
  "response_format": { "type": "json_object" }
}

parameters.responseBody:
={
  const c = $json?.choices?.[0]?.message?.content;
  let parsed = {};
  try { parsed = JSON.parse(c); } catch (e) { parsed = { raw: c }; }
  return { ok: true, criativo: parsed };
}
